import{_ as n,o as i,c as r,ag as t}from"./chunks/framework.DXGyWiRo.js";const s="/images/uebung040.jpg",a="/images/uebung041.jpg",d="/images/uebung042.jpg",c=JSON.parse('{"title":"Übung Lektion 25","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung25.md","filePath":"lektionen/uebung25.md"}'),l={name:"lektionen/uebung25.md"};function o(u,e,h,p,m,b){return i(),r("div",null,[...e[0]||(e[0]=[t('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-25" tabindex="-1">Übung Lektion 25 <a class="header-anchor" href="#ubung-lektion-25" aria-label="Permalink to &quot;Übung Lektion 25&quot;">​</a></h1><p>A) Ergänzen Sie die Deklinationsbeispiele von <a href="./lektion16">Lektion 16</a>, Wiederholungsübung A durch Hinzufügen von 4. Dativ (चतुर्थी) und 5. Ablativ (पञ्चमी). Bilden Sie außerdem Deklinationsreihen mit allen bisher gelernten Formen zu</p><p>१. सन्त् (m., n.)</p><p>२. महान्त् (m., n.)</p><p>३. यद् (m., n., f.)</p><p>Lernen Sie diese Deklinationsparadigmen auswendig!</p><p>B) Übersetzen Sie und lösen Sie die Komposita in Sanskrit auf:</p><p>गुर्वादेशाद्रामो ग्रामान्नगरं गत्वा साधुगृहं प्रविश्य साधुमुपस्थायालं क्रोधेनेति वक्ति ॥१॥ Auf Anweisung des Lehrers geht Rāma aus dem Dorf in die Stadt, betritt das Haus des Heiligen, stellt sich ehrerbietig vor deen Heiligen und spricht: &quot;Genug des Zornes!&quot;</p><p>गुरोरधर्मः श्रोतुं न शक्यत इति श्रुत्या च स्मृतिभिश्चोद्यते ॥२॥ Der Veda und die Tradition sagen, dass man von einem Meister nichts Unrechtes hören kann.</p><p>क्षत्रिया जनाञ्छत्रुभ्यो रक्षितुमर्हन्तीति क्षत्रियधर्मः ॥३॥ Pflicht der Kṣatriyas ist, dass die Kṣatriyas das Volk vor den Feinden schützen sollen.</p><p>कृतयज्ञदोषत्वाद्ब्राह्मणो धनं लब्धुं नार्हति ॥४॥ Da er einen Opferfehler begangen hat, braucht der Brahmane kein Geld bekommen.</p><p>धनलाभहेतोस्ते वैश्या व्रतं कृत्वा ब्रह्मचर्यं चरन्ति ॥५॥ Um reich zu werden, haben diese Vaśyas ein Gelübde gemacht und enthalten sich sexuell.</p><p>बुद्द्धाश्चार्हन्तश्च दुःखान्मुक्ताः । मुञ्चन्ती बुद्धिर्हि तैः प्राप्ता ॥६॥ Buddhas und Arhants sind vom Leid befreit. Sie haben nämlich die erlösende Einsicht erreicht.</p><p>लोभेन च क्रोधेन च मोहेन च जना दुष्यन्ति । ततः प्राप्तकाला नरकं पतन्ति ॥७॥ Durch Gier, Hass und Verblendung verderben Menschen. Wenn die Zeit gekommen ist fallen sie dann in eine Hölle.</p><p>क्षत्रियो महानगरतः शत्रुग्रामं योद्धुं शूरयोधानानयति ॥८॥ Der Kṣatriya bringt heldenhafte Krieger aus der Großstadt, um das Dorf der Feinde zu bekämpfen.</p><p>पुत्रलाभकारणाद्ब्राह्मणी व्रतं चरति ॥९॥ Um einen Sohn zu bekommen, hält die Brahmanin ein Gelübde (d.h. sie fastet).</p><p>लब्धपुत्रत्वाद्द्विजेन महासुखमाप्तम् ॥१०॥ Wenn ein Zweimalgeborener einen Sohn bekommt, überkommt ihn großes Glück.</p><p>विष्णुर्भक्तान्मरणात्पाति ॥११॥ Viṣṇu bewahrt seine Gläubigen vor dem Tod.</p><p>रामाद्विना =  रामं विना = रामेण विना ॥१२॥ Ohne Rāma.</p><p>साधोः शिक्षा गुणाय संपद्यते नासाधोः ॥१३॥ Der Unterricht eines Heiligen gereicht zur Tugend, nicht der eines Unheiligen.</p><p>रामः कृष्णाय तिष्ठति ॥१४॥ Rāma wartet auf Kṛṣṇa.</p><p>सुखेन गच्छति ॥१५॥ Es geht leicht.</p><p>अलं भयेन ॥१६॥ Hör auf mit der Angst!</p><p>लोकादधिको हरिः ॥१७॥ (हरि m. = विष्णु / कृष्ण) Größer als die Welt ist Hari.</p><p><img src="'+s+'" alt=""><br> Abb.: लोभेन च क्रोधेन च मोहेन च जना दुष्यन्ति<br> Hindus und Sikhs verbrennen einen Koran<br> [Bildquelle: saraab. -- <a href="http://www.flickr.com/photos/saraab/783886367/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/saraab/783886367/</a>.  -- Zugriff am 2008-12-24. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>यतो यतो निवर्तते<br> ततस्ततो विमुच्यते ।<br> निवर्तनाद्धि सर्वतो<br> न वेत्ति दुःखमण्वपि ॥१॥</p><p>Wovon man sich zurückzieht, davon wird man befreit. Wenn man sich nämlich von allem zurückzieht, dann kennt man kein Leid, und sei&#39;s so klein wie ein Atom.</p><p>मानाद्वा यदि वा लोभात्<br> क्रोधाद्वा यदि वा भयात् ।<br> यो न्यायमन्यथा ब्रूते<br> स याति नरकं नरः ॥२॥</p><p>Wenn jemand aus Hochmut, Gier, Zorn oder Furcht ein falsches Gerichtsurteil spricht, dann kommt er in eine Hölle.</p><p>भवन्ति नरकाः पापात्<br> पापं दारिद्र्यसंभवम् ।<br> दारिद्र्यमप्रदानेन ॥३॥</p><p>Höllen entstehen wegen des Bösen, Böses entsteht aus Armut, Armut entsteht aus Nicht-Geben.</p><p>शासनाद्वा विमोक्षाद्वा<br> स्तेनः स्तेयाद्विमुच्यते ।<br> अशासित्वा तु तं राजा<br> स्तेनस्याप्नोति किल्बिषम् ॥मनुस्मृति ८.३१६॥ ॥४॥</p><p>Ein Dieb wird von der Diebstahlsschuld befreit durch Bestrafung oder durch Freilassung. Wenn ihn aber der König nicht bestraft, dann übernimmt er die Schuld des Diebes.</p><p><img src="'+a+'" alt=""><br> Abb.: भवन्ति नरकाः पापात्<br> पापं दारिद्र्यसंभवम् ।<br> दारिद्र्यमप्रदानेन ॥<br> Agra = आगरा<br> [Bildquelle: Trinitas Imaging / Udit Kulshrestha. -- <a href="http://www.flickr.com/photos/uditk/2246685556/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/uditk/2246685556/</a>. -- Zugriff am 2008-12-24. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>1. कौटिलीयार्थशास्त्र १.४.१. über den Nutzen der Ökonomie:</p><p>वार्त्ता धान्यपुशुहिरण्यकुप्यविष्टिप्रदानादौपकारिकी ॥</p><p>Die Wirtschaft ist nützlich, weil sie Getreide, Vieh, Gold, Metalle, Arbeit hervorbringt.</p><p>2. कौटिलीयार्थशास्त्र १.५. über die Ausbildung eines Fürsten:</p><p>तस्माद्दण्डमूलास्तिस्रो विद्याः ॥१॥ विनयमूलो दण्डः प्राणभृतां योगक्षेमावहः ॥२॥ कृतकः स्वभाविकश्च विनयः ॥३॥ क्रिया हि द्रव्यं विनयति नाद्रव्यम् ॥४॥ शुश्रूषाश्रवणग्रहणविज्ञानोहापोहतत्त्वाभिनिविष्टबुद्धिं विद्या विनयति नेतरम् ॥५॥ ... ॥ वृत्तचौलकर्मा लिपिं संख्यानं चोपयुन्ञ्जीत ॥७॥ वृत्तोपनयस्त्रयीमान्वीक्षिकीं च शिष्टेभ्यो वार्त्तामध्यक्षेभ्यो दण्डनीतिं वक्तृप्रयोक्तृभ्यः ॥८॥ ब्रह्मचर्यं चा षोडशाद्वर्षाद् ॥९॥ अतो गोदानं दारकर्म चास्य ॥१०॥ नित्यश्च विद्यावृद्धसंयोगो विनयवृद्ध्यर्थम्, तन्मूलत्वाद्विनयस्य ॥११॥ ... ॥ श्रुताद्धि प्रज्ञोपजायते प्रज्ञाया योगो योगादात्मवत्तेति विद्यानां सामर्थ्यम् ॥१६॥ ... ॥ विद्याविनयहेतुरिन्द्रियजयः कामक्रोधलोभमानमदहर्षत्यागात्कार्यः ॥१.६.१.॥</p><p>Deswegen haben die drei Wissenschaften den Stock als Grundlage. Der Stock, der die Grundlage von gutem Verhalten ist, bringt den Lebewesen Erwerb und sicheren Besitz. Gutes Verhalten ist erarbeitet bzw. angeboren. Tätigkeit erzieht nämlich ein geeignetes Material, kein ungeeignetes. Wissen erzieht einen Geist, der durch Gehorsam, Zuhören, Bergreifen, Verstehen und Überlegen zur Wahrheit gekommen ist, nicht einen anderen. ... Nach der Haarschneidezeremonie soll er sich Schreiben und Rechnen aneignen. Nach dem Upanayana sill er sich von Gelehrten Vedistik und Philosophie aneignen, Ökonomie von den Departementschefs, Politik von Theoretikern und Praktikern. Er lebe zölibatär bis zum 16. Lebensjahr. Darauf erfolge Godāna und Heirat. Stets bleibe er mit im Wissen Alten verbunden, damit sein gutes Verhalten wachse, denn gutes Verhalten hat seine Grundlage darin. ... Aus Gehörten entsteht nämlich Erkenntnis, aus Erkenntnis Praxis, aus Praxis Selbstbesitz; so entsprechen die Wissenschaften ihrem Zweck. ... Wissen und gutes Verhalten ist die Ursache für den Sieg über die Sinne. Dieser ist nötig, um Lüsternheit, Hass, Gier, Einbildung, Rausch und Erregung abzulegen.</p><p><img src="'+d+'" alt=""><br> Abb.: वार्त्ता धान्यपुशुहिरण्यकुप्यविष्टिप्रदानादौपकारिकी ॥<br> [Bildquelle: World Bank Photo Collection. -- Zugriff am 2008-12-24. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>Lösung zu den <a href="./uebung26">Übungen Lektion 26 - 30</a></p>',43)])])}const k=n(l,[["render",o]]);export{c as __pageData,k as default};
